checker_dsl:
OR {
  EXISTS (`class C`, `method existingMethod`) {
    AND {
      NOT {
        EXISTS (`equals method E`) {
          (`equals method E is declared in class C`)
        }
      },
      EXISTS (`hashCode method H`) {
        AND {
          (`hashCode method H is declared in class C`),
          (`hashCode method H is the same method as existingMethod`)
        }
      }
    }
  },
  EXISTS (`class C`, `method existingMethod`) {
    AND {
      NOT {
        EXISTS (`hashCode method H`) {
          (`hashCode method H is declared in class C`)
        }
      },
      EXISTS (`equals method E`) {
        AND {
          (`equals method E is declared in class C`),
          (`equals method E is the same method as existingMethod`),
          NOT {
            (`equals method E is a refining equals method`)
          }
        }
      }
    }
  }
}
